                label: 'Início',
                svgFilled: _svgBrowseFilled,
                svgOutline: _svgBrowseOutline,
                active: tab == 0,
                onTap: () => onTab(0),
              ),
              _NavFeedPill(
                active: tab == 1,
                onTap: () => onTab(1),
              ),
              _NavIcon(
                label: 'Exibição',
                svgFilled: svgExibicaoFilled,
                svgOutline: svgExibicaoOutline,
